        xList.Sort((x1, x2) => -1 * x1.p.CompareTo(x2.p));

        // Create a single Random object to ensure different outcomes on each call
        Random random = new Random();

        // Choose an item randomly based on probabilities
        X chosenItem1 = ChooseRandomlyBasedOnProbability(xList, random);
